  "inlineSchema": "// Prisma schema cho trang giới thiệu quê hương Trà Vinh\n// Kết nối với Neon: đặt DATABASE_URL trong biến môi trường (.env)\n// Sau khi cắm Neon, chạy:\n//   npx prisma generate\n//   npx prisma db push        (tạo bảng)\n//   npx prisma db seed        (nạp dữ liệu mẫu - xem prisma/seed.ts)\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n/// Nội dung chung của trang (hero, giới thiệu, liên hệ...).\n/// Dùng 1 bản ghi duy nhất với id = \"singleton\".\nmodel SiteContent {\n  id String @id @default(\"singleton\")\n\n  // Hero\n  heroKicker       String @default(\"Miền đất chín rồng\")\n  heroTitle        String @default(\"Trà Vinh\")\n  heroSubtitle     String @default(\"Nơi phù sa sông Hậu gặp gỡ hồn Khmer, những hàng cây cổ thụ và mùi biển mặn Ba Động.\")\n  heroImage        String @default(\"/images/hero-tra-vinh.png\")\n  logoImage        String @default(\"/logo.png\")\n  locationMapImage String @default(\"/images/map.jpg\")\n\n  // Giới thiệu tổng quan\n  aboutHeading String @default(\"Vùng đất của cây và nước\")\n  aboutBody    String @default(\"Trà Vinh nằm giữa hai dòng sông Tiền và sông Hậu, là nơi giao thoa của ba dân tộc Kinh - Khmer - Hoa. Những ngôi chùa Khmer trăm tuổi, hàng cây sao dầu cổ thụ và những vườn dừa sáp trĩu quả tạo nên một bản sắc không nơi nào có được.\")\n\n  // Liên hệ\n  contactHeading String @default(\"Ghé thăm Trà Vinh\")\n  contactBody    String @default(\"Cách TP. Hồ Chí Minh khoảng 130km về phía Tây Nam. Thời điểm đẹp nhất để ghé thăm là vào mùa lễ Ok Om Bok (tháng 10 âm lịch).\")\n  contactEmail   String @default(\"hello@travinh.travel\")\n  contactPhone   String @default(\"+84 294 3862 xxx\")\n  mapEmbedUrl    String @default(\"https://www.openstreetmap.org/export/embed.html?bbox=106.20%2C9.85%2C106.45%2C9.98&layer=mapnik\")\n\n  updatedAt DateTime @updatedAt\n}\n\n/// Địa điểm nổi bật\nmodel Location {\n  id             String   @id @default(cuid())\n  title          String\n  description    String\n  content        String   @default(\"\")\n  image          String\n  tag            String   @default(\"Điểm đến\")\n  order          Int      @default(0)\n  mapTop         Float?\n  mapLeft        Float?\n  floatingImage1 String?\n  floatingImage2 String?\n  floatingImage3 String?\n  createdAt      DateTime @default(now())\n}\n\n/// Văn hóa & lễ hội\nmodel Festival {\n  id          String   @id @default(cuid())\n  title       String\n  description String\n  content     String   @default(\"\")\n  image       String\n  season      String   @default(\"\")\n  order       Int      @default(0)\n  mapTop      Float?\n  mapLeft     Float?\n  createdAt   DateTime @default(now())\n}\n\n/// Ẩm thực đặc sản\nmodel Food {\n  id          String   @id @default(cuid())\n  title       String\n  description String\n  image       String\n  order       Int      @default(0)\n  mapTop      Float?\n  mapLeft     Float?\n  createdAt   DateTime @default(now())\n}\n\n/// Ảnh trong thư viện ảnh\nmodel GalleryImage {\n  id        String   @id @default(cuid())\n  image     String\n  caption   String   @default(\"\")\n  order     Int      @default(0)\n  createdAt DateTime @default(now())\n}\n\n/// Tour du lịch\nmodel Tour {\n  id          String   @id @default(cuid())\n  title       String\n  description String\n  price       String   @default(\"Liên hệ\")\n  duration    String   @default(\"1 Ngày\")\n  image       String\n  order       Int      @default(0)\n  mapTop      Float?\n  mapLeft     Float?\n  createdAt   DateTime @default(now())\n}\n\n/// Sản phẩm đặc sản (Shop)\nmodel Product {\n  id          String   @id @default(cuid())\n  title       String\n  description String\n  price       String   @default(\"Liên hệ\")\n  image       String\n  order       Int      @default(0)\n  mapTop      Float?\n  mapLeft     Float?\n  createdAt   DateTime @default(now())\n}\n\n/// Người dùng đăng ký\nmodel User {\n  id            String         @id @default(cuid())\n  name          String?\n  email         String?        @unique\n  password      String?\n  emailVerified DateTime?\n  image         String?\n  accounts      Account[]\n  sessions      Session[]\n  productOrders ProductOrder[]\n  tourBookings  TourBooking[]\n  createdAt     DateTime       @default(now())\n}\n\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String? @db.Text\n  access_token      String? @db.Text\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String? @db.Text\n  session_state     String?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\n/// Đơn hàng Mua Đặc Sản\nmodel ProductOrder {\n  id     String  @id @default(cuid())\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  customerName  String\n  customerPhone String\n  customerNote  String?\n\n  items       OrderItem[]\n  totalAmount Int         @default(0)\n  status      String      @default(\"PENDING\")\n  createdAt   DateTime    @default(now())\n  updatedAt   DateTime    @updatedAt\n}\n\nmodel OrderItem {\n  id          String       @id @default(cuid())\n  orderId     String\n  order       ProductOrder @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  productId   String\n  productName String\n  price       Int          @default(0)\n  quantity    Int          @default(1)\n}\n\n/// Đặt Tour Du Lịch\nmodel TourBooking {\n  id     String  @id @default(cuid())\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  customerName  String\n  customerPhone String\n  customerNote  String?\n\n  tourId       String\n  tourName     String\n  tourDate     String\n  participants Int\n  totalAmount  Int    @default(0)\n\n  status    String   @default(\"PENDING\")\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n",
